files = [f for f in os.listdir(PLATFORMS_DIR) if f.endswith('.html')]
for fname in files:
    path = os.path.join(PLATFORMS_DIR, fname)
    with open(path, 'r', encoding='utf-8') as f:
        content = f.read()
    pattern = r'      <div class="nav__mobile-panel" id="mobile-panel"[^\n]*\n.*?      </div>\n    </div>\n  </div>\n</header>'
    replacement = NEW_PANEL + '\n    </div>\n  </div>\n</header>'
    new_content, count = re.subn(pattern, replacement, content, flags=re.DOTALL)
    if count:
        with open(path, 'w', encoding='utf-8') as f:
            f.write(new_content)
        print(f"Updated {fname} ({count} replacement)")
    else:
        print(f"NO MATCH in {fname}")
